from fastapi import FastAPI
import subprocess

app = FastAPI()

@app.get("/api/wifi")
async def get_wifi_stats():
    result = subprocess.run(["/usr/local/bin/wdutil", "info"], capture_output=True, text=True)

    stats = {
        "ssid": "",
        "bssid": "",
        "rssi": 0,
        "channel": 0,
        "tx_rate": 0,
        "security": ""
    }

    lines = result.stdout.split("\n")
    for line in lines:
        if line.startswith("Current SSID:"): stats["ssid"] = line.split(": ")[1]
        if line.startswith("BSSID:"): stats["bssid"] = line.split(": ")[1]
        if line.startswith("RSSI:"): stats["rssi"] = int(line.split(" ")[1].replace("dBm", ""))
        if line.startswith("Channel:"): stats["channel"] = int(line.split(": ")[1])
        if line.startswith("TX Rate:"): stats["tx_rate"] = int(line.split(" ")[1].replace("Mbps", ""))
        if line.startswith("Security:"): stats["security"] = line.split(": ")[1]

    return stats

if __name__ == "__main__":
    import uvicorn
    uvicorn.run(app, host="0.0.0.0", port=8000)

import { useState, useEffect } from 'react';

export default function Home() {
  const [wifiStats, setWifiStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetch('http://localhost:8000/api/wifi');
        const data = await response.json();
        setWifiStats(data);
        setLoading(false);
      } catch (error) {
        console.error('Error fetching Wi-Fi stats:', error);
        setLoading(false);
      }
    };

    const interval = setInterval(fetchData, 3000);
    fetchData(); // Initial fetch

    return () => clearInterval(interval);
  }, []);

  if (loading) {
    return <div>Loading Wi-Fi stats...</div>;
  }

  if (!wifiStats) {
    return <div>Failed to retrieve Wi-Fi stats.</div>;
  }

  return (
    <div className="p-6 max-w-md mx-auto">
      <div className="bg-white shadow rounded-lg p-4">
        <h2 className="text-xl font-bold mb-4">Wi-Fi Network</h2>
        <div className="space-y-3">
          <div>
            <span className="font-semibold">SSID:</span> {wifiStats.ssid}
          </div>
          <div>
            <span className="font-semibold">BSSID:</span> {wifiStats.bssid}
          </div>
          <div>
            <span className="font-semibold">Signal Strength:</span> {wifiStats.rssi} dBm
          </div>
          <div>
            <span className="font-semibold">Channel:</span> {wifiStats.channel}
          </div>
          <div>
            <span className="font-semibold">TX Rate:</span> {wifiStats.tx_rate} Mbps
          </div>
          <div>
            <span className="font-semibold">Security:</span> {wifiStats.security}
          </div>
        </div>
      </div>
    </div>
  );
}
